<script>
(function(){ function refreshReclamacion(){ var reclamacion=document.getElementById('reclamacion'); var origen=document.getElementById('reclamacion_origen'); var wrap=document.getElementById('reclamacion_fields'); var candidatoOtro=document.getElementById('candidato_otro_wrap'); var fotoNuestra=document.getElementById('foto_nuestra_wrap'); if(!reclamacion){return;} var enabled=reclamacion.value==='1'; wrap.style.display=enabled?'':'none'; var origenVal=origen?origen.value:''; candidatoOtro.style.display=enabled&&origenVal==='otro'?'':'none'; fotoNuestra.style.display=enabled&&origenVal==='nuestra'?'':'none'; } document.addEventListener('change', function(e){ if(e.target && (e.target.id==='reclamacion' || e.target.id==='reclamacion_origen')){ refreshReclamacion(); }}); refreshReclamacion(); })();
</script>
